openclaw config schema 2>&1 | python3 -c "
import json, sys
schema = json.load(sys.stdin)

# 查找 sessions_spawn 相关路径
def find_paths(s, path='#'):
    results = []
    if isinstance(s, dict):
        for k, v in s.items():
            p = f'{path}.{k}'
            if isinstance(v, str) and 'maxResults' in v:
                print('  STR:', p, '=', v)
            if 'sessions_spawn' in str(k).lower() or 'sessions_spawn' in str(v).lower():
                results.append(p)
            results.extend(find_paths(v, p))
        if 'properties' in s:
            for k in s['properties']:
                if 'spawn' in k.lower():
                    results.append(f'{path}.properties.{k}')
    return results

paths = find_paths(schema)
print('Found sessions_spawn related:')
for p in paths:
    print(f'  {p}')
if not paths:
    print('  (none found - sessions_spawn is not in schema)')
" 2>&1

