python3 -c "
import json
files = __import__('glob').glob('/root/.openclaw/agents/father/sessions/*.jsonl')
files.sort(key=lambda f: __import__('os').path.getmtime(f), reverse=True)

with open(files[0]) as f:
    for line in f:
        d = json.loads(line)
        if d.get('type') == 'trace.metadata':
            prompt = d.get('data', {}).get('prompting', {})
            report = prompt.get('systemPromptReport', {})
            ws = report.get('injectedWorkspaceFiles', [])
            if ws:
                print('=== 自动注入的文件 ===')
                for w in ws:
                    print(f'  {\"✅\" if not w.get(\"missing\") else \"❌\"} {w[\"name\"]} ({w.get(\"injectedChars\",0)} chars) | path={w.get(\"path\",\"?\")}')
                print()
                heart_found = [w for w in ws if 'heart' in w.get('name','').lower() or 'heart' in w.get('path','').lower()]
                if heart_found:
                    print('✅ heart/ 被注入')
                    for h in heart_found:
                        print(f'   {h[\"name\"]}')
                else:
                    print('❌ heart/ 没有被自动注入')
            else:
                print('没有找到 injectedWorkspaceFiles，换方式查')
                # 看看有哪些 key
                for k in (report or {}).keys():
                    print(f'  report key: {k}')
            break
" 2>/dev/null

